import {readFile, unlink, writeFile} from 'node:fs/promises';
import {build} from 'esbuild';

const entry = 'question/type/codejudge/amd/src/codemirror6_entry.js';
const temp = 'question/type/codejudge/amd/src/codemirror6.bundle.tmp.js';
const sourceOut = 'question/type/codejudge/amd/src/codemirror6.js';
const buildOut = 'question/type/codejudge/amd/build/codemirror6.min.js';

const banner = `/**
 * CodeMirror 6 bundle for qtype_codejudge.
 *
 * Generated by tools/build-codemirror6.mjs. Do not edit manually.
 *
 * @package     qtype_codejudge
 * @copyright   2026 IA Judge Contributors
 * @license     https://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
`;

await build({
    entryPoints: [entry],
    bundle: true,
    format: 'iife',
    globalName: 'CodeJudgeCodeMirror6',
    outfile: temp,
    sourcemap: false,
    logLevel: 'silent',
});

const bundled = await readFile(temp, 'utf8');
await writeFile(sourceOut, `${banner}\ndefine([], function() {\n${bundled}\n    return CodeJudgeCodeMirror6;\n});\n`);

await build({
    entryPoints: [entry],
    bundle: true,
    format: 'iife',
    globalName: 'CodeJudgeCodeMirror6',
    outfile: temp,
    minify: true,
    sourcemap: false,
    logLevel: 'silent',
});

const minified = await readFile(temp, 'utf8');
await writeFile(buildOut, `define([],function(){${minified}return CodeJudgeCodeMirror6;});\n`);
await unlink(temp);
